server/tests/test_service.py :: test_convert_image_invalid_format
def test_convert_image_invalid_format() -> None:
    try:
        convert_image(b"abc", "x.png", "bmp")
    except ConversionError as error:
        assert error.status_code == 400
    else:
        raise AssertionError("Expected ConversionError")

server/tests/test_service.py :: test_convert_image_empty_payload
def test_convert_image_empty_payload() -> None:
    try:
        convert_image(b"", "x.png", "png")
    except ConversionError as error:
        assert "No file uploaded" in str(error)
    else:
        raise AssertionError("Expected ConversionError")
